{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires deriving a scaling law for the critical exponent in dissipative PDEs based on dimension n and diffusion order s, then verifying it against specific physical models.",
  "helpers": [
    {
      "label": "derive_scaling_law",
      "instructions": "Perform a dimensional analysis on a generalized dissipative PDE of the form du/dt + (u dot grad)u + (-Delta)^s u = 0. Determine the scaling exponent alpha such that if u(x, t) is a solution, then u_lambda(x, t) = lambda^alpha u(lambda x, lambda^(2s) t) is also a solution. Express the critical regularity exponent or the scaling-invariant norm exponent in terms of n and s."
    },
    {
      "label": "verify_specific_pdes",
      "instructions": "Apply the derived scaling law formula to the following six specific cases to find their respective critical exponents: 1. 3D Navier-Stokes (n=3, s=1), 2. 2D Navier-Stokes (n=2, s=1), 3. 1D Burgers (n=1, s=1), 4. Surface Quasi-Geostrophic SQG (n=2, s=1/2), 5. Magnetohydrodynamics MHD (n=3, s=1), 6. Fractional Navier-Stokes (n=3, arbitrary s). For each, identify the dimension n and the diffusion order s and compute the exponent using the general formula."
    },
    {
      "label": "consistency_check",
      "instructions": "Compare the exponents calculated in the verification step against known literature values for the critical scaling of these specific PDEs to ensure the general formula is correct and universally applicable."
    }
  ],
  "synthesis_brief": "The parent will take the general formula derived in helper 1, the list of calculated exponents from helper 2, and the validation results from helper 3 to provide the final universal formula and a table of verified instances."
}

